import{_ as e,c as a,a as s,o as i}from"./app-CEcM0piI.js";const n={};function d(l,t){return i(),a("div",null,t[0]||(t[0]=[s(`<p>结合了Lambda表达式，简化集合、数组的操作 利用Stream流中的API进行各种操作</p><p>分为中间方法和终结方法</p><ul><li>中间方法 : 方法调用完毕之后，还可以调用其他方法</li><li>终结方法 : 最后一步，调用完毕之后，不能调用其他方法</li></ul><h4 id="获取stream流" tabindex="-1"><a class="header-anchor" href="#获取stream流"><span>获取stream流</span></a></h4><table><thead><tr><th>获取方式</th><th>方法名</th><th>说明</th></tr></thead><tbody><tr><td>单列集合</td><td>default Stream&lt;E&gt; stream()</td><td>Collection中的默认方法</td></tr><tr><td>双列集合</td><td>无</td><td>无法直接使用stream流</td></tr><tr><td>数组</td><td>public static &lt;T&gt; Stream&lt;T&gt; stream(T[ ] array)Arrays</td><td>工具类中的静态方法</td></tr><tr><td>一堆零散数据</td><td>public static&lt;T&gt; Stream&lt;T&gt; of(T... values)</td><td>Stream接口中的静态方法</td></tr><tr><td>双列集合若想要使用stream流需要使用keySet()或entrySet()获取单列集合再获取stream流</td><td></td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Stream&lt;String&gt; stream1=list.stream();</span></span>
<span class="line"><span>list.stream().forEach(s -&gt;System.out.println(s));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="中间方法" tabindex="-1"><a class="header-anchor" href="#中间方法"><span>中间方法</span></a></h4><table><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td>Stream&lt;T&gt; filter(Predicate&lt;? super T&gt; predicate)</td><td>过滤</td></tr><tr><td>Stream&lt;T&gt; limit(long maxSize)</td><td>获取前几个元素</td></tr><tr><td>Stream&lt;T&gt; skip(long n)</td><td>跳过前几个元素</td></tr><tr><td>Stream&lt;T&gt; distinct()</td><td>元素去重，依赖(hashcode和equals方法)</td></tr><tr><td>static &lt;T&gt; Stream&lt;T&gt; concat(Stream a, Stream b)</td><td>合并a和b两个流为一个流</td></tr><tr><td>Stream&lt;R&gt; map(Function&lt;T , R&gt; mapper)</td><td>转换流中的数据类型,或者对数据流进行处理返回新的数据</td></tr></tbody></table><p>中间方法，返回新的Stream流，原来的Stream流只能使用一次，建议使用链式编程 修改stream流中的数据，不会影响原来集合或者数组中的数据</p><h4 id="终结方法" tabindex="-1"><a class="header-anchor" href="#终结方法"><span>终结方法</span></a></h4><table><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td>void forEach(Consumer action)</td><td>遍历</td></tr><tr><td>long count()</td><td>统计</td></tr><tr><td>toArray()</td><td>收集流中的数据，放到数组中</td></tr><tr><td>collect(Collector collector)</td><td>收集流中的数据，放到集合中</td></tr></tbody></table><h1 id="方法引用" tabindex="-1"><a class="header-anchor" href="#方法引用"><span>方法引用</span></a></h1><p>:: 方法引用符</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class FunctionDemo1{</span></span>
<span class="line"><span>	public static int subtraction(int num1，int num2){</span></span>
<span class="line"><span>		return num2-num1;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	public static void main(){</span></span>
<span class="line"><span>		Arrays.sort(arr,FunctionDemo1::subtraction);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="引用静态方法" tabindex="-1"><a class="header-anchor" href="#引用静态方法"><span>引用静态方法</span></a></h2><p>类名::静态方法</p><h2 id="引用成员方法" tabindex="-1"><a class="header-anchor" href="#引用成员方法"><span>引用成员方法</span></a></h2><p>格式：<code>对象::成员方法</code></p><ul><li>其他类：<code>其他类对象::方法名</code></li><li>本类：<code>this::方法名</code></li><li>父类：<code>super::方法名</code></li></ul><h2 id="引用构造方法" tabindex="-1"><a class="header-anchor" href="#引用构造方法"><span>引用构造方法</span></a></h2><p>格式：<code>类名::new</code> 示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Student::new</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="引用数组的构造方法" tabindex="-1"><a class="header-anchor" href="#引用数组的构造方法"><span>引用数组的构造方法</span></a></h2><p>格式：<code>数据类型[]::new</code></p><p>示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span> int[]::new</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="异常" tabindex="-1"><a class="header-anchor" href="#异常"><span>异常</span></a></h1><p>![[Clip_2024-10-13_13-10-22.png]]</p><ul><li>Error：代表的系统级别错误（属于严重问题）系统一旦出现问题，sun公司会把这些错误封装成Error对象。Error是给sun公司自己用的，不是给我们程序员用的。因此我们开发人员不用管它。</li><li>Exception：叫做异常，代表程序可能出现的问题。我们通常会用Exception以及他的子类来封装程序出现的问题。</li><li>运行时异常：RuntimeException本身和子类编译阶段没有错误提示，运行时出现的（如：数组索引越界异常）</li><li>编译时异常：没有继承RuntimeExcpetion的异常，直接继承于Excpetion。编译阶段就会错误提示</li></ul><p>异常是用来查询bug的关键参考信息 异常可以作为方法内部的一种特殊返回值，以便通知调用者底层的执行情况</p><p><strong>JVM默认的处理方式</strong> 把异常的名称，异常原因及异常出现的位置等信息输出在了控制台 程序停止执行，下面的代码不会再执行了</p><p><strong>自己处理异常</strong> 捕获异常</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>try{</span></span>
<span class="line"><span>	可能出现异常的代码;</span></span>
<span class="line"><span>}catch(异常类名 变量名){</span></span>
<span class="line"><span>	异常的处理代码;</span></span>
<span class="line"><span>}finally{</span></span>
<span class="line"><span>	无论有没有异常都会执行的代码;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>抛出异常</p><p>throws 写在方法定义处，表示声明一个异常告诉调用者，使用本方法可能会有哪些异常 编译时异常：必须要写 运行时异常：可以不写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public void 方法()throws 异常类名1,异常类名2...{</span></span>
<span class="line"><span>	...</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>throw 写在方法内，结束方法 手动抛出异常对象，交给调用者 方法中下面的代码不再执行了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public void 方法(){</span></span>
<span class="line"><span>	throw new NullPointerException();</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="异常中常用方法" tabindex="-1"><a class="header-anchor" href="#异常中常用方法"><span>异常中常用方法</span></a></h4><h5 id="throwable中的成员方法" tabindex="-1"><a class="header-anchor" href="#throwable中的成员方法"><span>Throwable中的成员方法</span></a></h5><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public String getMessage()</td><td>返回此 throwable 的详细消息字符串</td></tr><tr><td>public String tostring()</td><td>返回此可抛出的简短描述</td></tr><tr><td>public voidprintstackTrace()</td><td>把异常的错误信息输出在控制台(和jvm默认处理的一样但不会停止运行)</td></tr></tbody></table><h2 id="自定义异常" tabindex="-1"><a class="header-anchor" href="#自定义异常"><span>自定义异常</span></a></h2><p>自定义异常时要根据实际情况选择继承哪个异常 如果是运行时异常需要继承RuntimeException 如果是编译时异常需要继承Exception</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class NameFormatException extends RuntimeException{</span></span>
<span class="line"><span>	public NameFormatException() {}</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	public NameFormatException(String message){</span></span>
<span class="line"><span>		super(message);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="文件操作" tabindex="-1"><a class="header-anchor" href="#文件操作"><span>文件操作</span></a></h1><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public File(String pathname)</td><td>把字符串表示的路径变成File对象</td></tr><tr><td>public File(String parent, String child)</td><td>把父级路径和子级路径进行拼接</td></tr><tr><td>public File(Fileparent, String child)</td><td>把父级路径和子级路径进行拼接</td></tr></tbody></table><h4 id="判断和获取" tabindex="-1"><a class="header-anchor" href="#判断和获取"><span>判断和获取</span></a></h4><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public boolean isDirectory()</td><td>判断此路径名表示的File是否为文件夹</td></tr><tr><td>public boolean isFile()</td><td>判断此路径名表示的File是否为文件</td></tr><tr><td>public boolean exists()</td><td>判断此路径名表示的File是否存在</td></tr><tr><td>public long length()</td><td>返回文件的大小 (字节数量)</td></tr><tr><td>public String getAbsolutePath()</td><td>返回文件的绝对路径</td></tr><tr><td>public String getPath()</td><td>返回定义文件时使用的路径</td></tr><tr><td>public String getName()</td><td>返回文件的名称，带后缀</td></tr><tr><td>public long lastModified()</td><td>返回文件的最后修改时间 (时间毫秒值）</td></tr></tbody></table><h4 id="创建和删除" tabindex="-1"><a class="header-anchor" href="#创建和删除"><span>创建和删除</span></a></h4><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public boolean createNewFile()</td><td>创建一个新的空的文件如果存在则返回false,不存在则创建后返回true,如果没有给后缀名则创建无后缀名的文件</td></tr><tr><td>public boolean mkdir()</td><td>创建单级文件夹</td></tr><tr><td>public boolean mkdirs()</td><td>创建多级文件夹</td></tr><tr><td>public boolean delete()</td><td>删除文件、空文件夹</td></tr></tbody></table><h4 id="获取并遍历" tabindex="-1"><a class="header-anchor" href="#获取并遍历"><span>获取并遍历</span></a></h4><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td><mark>public File[] listFiles()</mark></td><td>获取当前该路径下所有内容存储到数组中<br></td></tr><tr><td>public static File[] listRoots()</td><td>列出可用的文件系统根如果时windows获取的就是盘符</td></tr><tr><td>public String[] list()</td><td>获取当前该路径下所有内容</td></tr><tr><td>public String[] list(FilenameFilter filter)</td><td>利用文件名过滤器获取当前该路径下所有内容</td></tr><tr><td>public File[] listFiles(FileFilter filter)</td><td>利用文件名过滤器获取当前该路径下所有内容</td></tr><tr><td>public File[] listFiles(FilenameFilter filter)</td><td>利用文件名过滤器获取当前该路径下所有内容</td></tr></tbody></table><ol><li>当调用者File表示的路径不存在时，返回null</li><li>当调用者File表示的路径是文件时，返回null</li><li>当调用者File表示的路径是一个空文件夹时，返回一个长度为0的数组</li><li>当调用者File表示的路径是一个有内容的文件夹时，将里面所有文件和文件夹的路径放在File数组中返回</li><li>当调用者File表示的路径是一个有隐藏文件的文件夹时，将里面所有文件和文件夹的路径放在File数组中返回，包含隐藏文件</li><li>当调用者File表示的路径是需要权限才能访问的文件夹时，返回null</li></ol><h1 id="io流" tabindex="-1"><a class="header-anchor" href="#io流"><span>IO流</span></a></h1><p>存储和读取数据的解决方案 用于读写文件中的数据（可以读写文件，或网络中的数据...)</p><p>按流的方向分分为输入流和输出流 按操作文件类型分分为字节流和字符流,字节流可以操控所有类型的文件,字符流只能操控纯文本文件</p><p>![[Clip_2024-10-13_15-32-47.png]]</p><h2 id="基本流" tabindex="-1"><a class="header-anchor" href="#基本流"><span>基本流</span></a></h2><h3 id="字节流" tabindex="-1"><a class="header-anchor" href="#字节流"><span>字节流</span></a></h3><p>![[Clip_2024-10-13_15-33-37.png]] 操作本地文件的字节输出流，可以把程序中的数据写到本地文件中。</p><p>当使用完io流对象后都需要手动关闭链接</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>f.close();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="fileoutputstream" tabindex="-1"><a class="header-anchor" href="#fileoutputstream"><span>FileOutputStream</span></a></h4><p>创建写入流对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>FileOutputStream fos =new FileoutputStream(name:&quot;myio//a.txt&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>直接指定对应路径的文件是使用写入方式打开的</p><p>参数是字符串表示的路径或者File对象都是可以的 如果文件不存在会创建一个新的文件，但是要保证父级路径是存在的。 如果文件已经存在，则会清空文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>FileOutputStream fos =new FileoutputStream(name:&quot;myio//a.txt&quot;,true)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在重载的构造函数中将第二个参数append的值设为true表示使用追加方式打开,这样打开文件的时候就不会清空文件,文件指针也放在文件末尾,当写入的时候从末尾添加</p><table><thead><tr><th>方法名</th><th>说明</th></tr></thead><tbody><tr><td>void write(int b)</td><td>一次写一个字节数据</td></tr><tr><td>void write(byte[] b)</td><td>一次写一个字节数组数据</td></tr><tr><td>void write(byte[] b, int off, int len)</td><td>一次写一个字节数组的部分数据,指明开始和写入长度</td></tr><tr><td>写入的内容是ascii码,如果要写入纯数字需要写该数字对应的ascii码</td><td></td></tr></tbody></table><p>要写入字符内容可以使用getBytes()转换为ascii再写入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>String str=&quot;abc123&quot;;</span></span>
<span class="line"><span>byte[] bytes=str.getBytes());</span></span>
<span class="line"><span>fos.write(bytes);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果要换行需要手写出来换行符</p><ul><li>windows : \\r\\n</li><li>Linux : \\n</li><li>Mac : \\r 在windows操作系统当中，java对回车换行进行了优化虽然完整的是\\r\\n，但是我们写其中一个\\r或者\\n，java也可以实现换行，因为java在底层会补全。</li></ul><h4 id="fileinputstream" tabindex="-1"><a class="header-anchor" href="#fileinputstream"><span>FileInputStream</span></a></h4><p>当创建流对象时如果文件不存在，就直接报错</p><table><thead><tr><th>方法</th><th>说明</th></tr></thead><tbody><tr><td>int read()</td><td>一次读取一字节数据,如果没有数据返回-1,每次读取数据都会使文件指针向后移1,返回的是ascii码,想要查看字符串类型需要强转</td></tr><tr><td>public int read(byte[] buffer)</td><td>一次读一个字节数组数据,返回读取的字节数</td></tr></tbody></table><p>如果文件打开了不释放会出现问题,所以在打开文件的时候通常会捕获异常,当操作出现异常的时候就释放文件描述符,但这样也会很麻烦</p><p>java7的时候添加了一个AutoCloseable的接口,实现了这个接口的类都可以在try的小括号里面创建对象,当try...catch语句执行完毕后会自动判断对象是否需要释放,如果需要释放就会自动释放</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>try (FileInputStream fis =new FileInputStream(name:&quot;D:\\\\itheima\\\\movie.mp4&quot;);</span></span>
<span class="line"><span>	FileOutputStream fos = new FileOutputStream( name: &quot;myiollcopy.mp4&quot;)) {</span></span>
<span class="line"><span>	//2.拷贝</span></span>
<span class="line"><span>	int len;</span></span>
<span class="line"><span>	byte[] bytes = new byte[1024 * 1024 * 5];</span></span>
<span class="line"><span>	while ((len = fis.read(bytes)) != -1){</span></span>
<span class="line"><span>		fos.write(bytes,off:0, len);</span></span>
<span class="line"><span>	}catch(IoException e){</span></span>
<span class="line"><span>		e.printStackTrace();</span></span>
<span class="line"><span>	}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>编码</p><table><thead><tr><th>String类中的方法</th><th>说明</th></tr></thead><tbody><tr><td>public byte[] getBytes()</td><td>使用默认方式进行编码</td></tr><tr><td>public byte[] getBytes(String charsetName)</td><td>使用指定方式进行编码</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>byte[]bytes2 = str.getBytes(charsetName:&quot;GBK&quot;);//使用gbk进行编码</span></span>
<span class="line"><span>System.out.println(Arrays.toString(bytes2));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>解码</p><table><thead><tr><th>String类中的方法</th><th>说明</th></tr></thead><tbody><tr><td>String(byte[] bytes)</td><td>使用默认方式进行解码</td></tr><tr><td>String(byte[] bytes, String charsetName)</td><td>使用指定方式进行解码</td></tr></tbody></table><h3 id="字符流" tabindex="-1"><a class="header-anchor" href="#字符流"><span>字符流</span></a></h3><p>出现乱码的两种情况:</p><ol><li>当读取数据时未读完整个汉字</li><li>编码和解码时的方式不统一</li></ol><p>对于第二个问题我们可以编码和解码的方式统一,所以解决乱码问题最主要的问题是第一个问题</p><p>字符流的底层其实就是字节流携带了字符集 字符流就可以在读取英文时只读取一个字节,读取中文时根据不同的字符集读取对应的字节数,这样就解决了第一个问题</p><p>输入流：一次读一个字节，遇到中文时，一次读多个字节 输出流：底层会把数据按照指定的编码方式进行编码，变成字节再写到文件中</p><p>![[Clip_2024-10-13_16-31-08.png]]</p><h4 id="filereader" tabindex="-1"><a class="header-anchor" href="#filereader"><span>FileReader</span></a></h4><p>创建字符输入流对象</p><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public FileReader(File file)</td><td>创建字符输入流关联本地文件</td></tr><tr><td>public FileReader(String pathname)</td><td>创建字符输入流关联本地文件</td></tr></tbody></table><p>读取数据</p><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public int read()</td><td>读取数据，读到末尾返回-1</td></tr><tr><td>public int read(char[] buffer)</td><td>读取多个数据，读到末尾返回-1</td></tr><tr><td>空参的方法读取后返回的还是十进制的编码,需要强转才能显示出内容</td><td></td></tr><tr><td>有参的方法读取后自动进行转码,所以是char数组</td><td></td></tr></tbody></table><p>释放资源</p><table><thead><tr><th>成员</th><th>说明</th></tr></thead><tbody><tr><td>public int close()方法</td><td>释放资源/关流</td></tr></tbody></table><h4 id="filewriter" tabindex="-1"><a class="header-anchor" href="#filewriter"><span>FileWriter</span></a></h4><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public Filewriter(File file)</td><td>创建字符输出流关联本地文件</td></tr><tr><td>public FileWriter(String pathname)</td><td>创建字符输出流关联本地文件</td></tr><tr><td>public FileWriter(File file, boolean append)</td><td>创建字符输出流关联本地文件，续写</td></tr><tr><td>public FileWriter(String pathname, boolean append)</td><td>创建字符输出流关联本地文件，续写</td></tr><tr><td></td><td></td></tr></tbody></table><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>void write(int c)</td><td>写出一个字符,如果是中文也是编码,如25105则写入一个&quot;我&quot;</td></tr><tr><td>void write(String str)</td><td>写出一个字符串</td></tr><tr><td>void write(String str, int off, int len)</td><td>写出一个字符串的一部分</td></tr><tr><td>void write(char[] cbuf)</td><td>写出一个字符数组</td></tr><tr><td>void write(char[] cbuf, int off, int len)</td><td>写出字符数组的一部分</td></tr><tr><td>自带了一个8196字节的缓冲区</td><td></td></tr><tr><td>无论写入还是写出底层都有一个缓冲区</td><td></td></tr><tr><td>可以使用成员方法手动刷新缓冲区</td><td></td></tr></tbody></table><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public void flush()</td><td>将缓冲区中的数据，刷新到本地文件中</td></tr><tr><td>public void close()</td><td>释放资源/关流</td></tr><tr><td>flush刷新：刷新之后，还可以继续往文件中写出数据</td><td></td></tr><tr><td>close关流：断开通道，无法再往文件中写出数据</td><td></td></tr></tbody></table><h2 id="高级流" tabindex="-1"><a class="header-anchor" href="#高级流"><span>高级流</span></a></h2><p>高级流都不用手动关闭,在生命周期结束它会自动关闭</p><h3 id="缓冲流" tabindex="-1"><a class="header-anchor" href="#缓冲流"><span>缓冲流</span></a></h3><p>高级流的一种</p><p>![[Clip_2024-10-13_16-52-29.png]] 字节缓冲输入流 字节缓冲输出流 字符缓冲输入流 字符缓冲输出流</p><p>缓冲流在原本的基本流上封装了一个缓冲区,这对性能有很大提升,但字符流本身就有缓冲区所以提示不是很明显</p><h4 id="字节缓冲流" tabindex="-1"><a class="header-anchor" href="#字节缓冲流"><span>字节缓冲流</span></a></h4><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public BufferedInputStream(InputStream is)</td><td>把基本流包装成高级流，提高读取数据的性能</td></tr><tr><td>public BufferedOutputStream(OutputStream os)</td><td>把基本流包装成高级流，提高写出数据的性能</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>BufferedInputStream bis =new BufferedInputStream(new FileInputStream(name:&quot;myio\\la.txt&quot;));</span></span>
<span class="line"><span>BufferedoutputStream bos =new BufferedoutputStream(new FileOutputStream(name:&quot;myio\\lcopy.txt&quot;));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="字符缓冲流" tabindex="-1"><a class="header-anchor" href="#字符缓冲流"><span>字符缓冲流</span></a></h4><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public BufferedReader(Reade r)</td><td>把基本流变成高级流</td></tr><tr><td>public Bufferedwriter(Writer r)</td><td>把基本流变成高级流</td></tr></tbody></table><p>字符缓冲输流特有方法</p><ul><li>public String. readLine() : 读取一行数据但不会读入换行符，如果没有数据可读了，会返回null</li></ul><p>字符缓冲输出流特有方法</p><ul><li>public void newLine() : 写入一个跨平台的换行</li></ul><h3 id="转换流" tabindex="-1"><a class="header-anchor" href="#转换流"><span>转换流</span></a></h3><p>转换流也是高级流的一种是字符流和字节流之间的桥梁</p><p>转换输入流InputStreamReader 转换输出流OutputStreamWriter 将字节流转换为字符流,在读取的时候转换为字符流读入,在写出的时候再转换为字节流写出,这样就能以字节流读写(都是以二进制形式),读入后使用转换的字符流也不会出现乱码问题</p><p>转换后字节流也可以使用字符流的方法了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//转换输入流</span></span>
<span class="line"><span>InputStreamReader isr = new InputStreamReader(new FileInputStream(&quot;myio\\\\gbkfile.txt&quot;), &quot;GBK&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//jdk11推出的方案,更简洁</span></span>
<span class="line"><span>//FileReader fr = new FileReader(&quot;myiol\\b.txt&quot;, Charset.forName(&quot;GBK&quot;));</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>//转换输出流</span></span>
<span class="line"><span>OutputStreamwriter osw = new OutputstreaamWriter(new FileoutputStream(&quot;myio\\\\b.txt&quot;),&quot;GBK&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//jdk11推出的方案更简洁</span></span>
<span class="line"><span>FileWriter fw= new FileWriter(&quot;myiollc.txt&quot;, Charset.forName(&quot;GBK&quot;));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="序列化流与反序列化流" tabindex="-1"><a class="header-anchor" href="#序列化流与反序列化流"><span>序列化流与反序列化流</span></a></h3><h4 id="序列化流objectlnputstream" tabindex="-1"><a class="header-anchor" href="#序列化流objectlnputstream"><span>序列化流ObjectlnputStream</span></a></h4><p>可以把Java中的对象写到本地文件中</p><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public Objectoutputstream(outputStream out)</td><td>把基本流包装成高级流</td></tr></tbody></table><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public final void writeobject(object obj)</td><td>把对象序列化（写出）到文件中去</td></tr></tbody></table><p>如果想要序列化写入一个类还需要让该类实现一个Serializable接口\\</p><p>Serializable接口里面是没有抽象方法，也就无需实现 这样的接口被称为标记型接口一旦实现了这个接口，那么就表示当前的Student类可以被序列化</p><h4 id="反序列化流objectoutputstream" tabindex="-1"><a class="header-anchor" href="#反序列化流objectoutputstream"><span>反序列化流ObjectOutputStream</span></a></h4><p>可以把序列化到本地文件中的对象，读取到程序中来</p><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public ObjectInputstream(Inputstream out)</td><td>把基本流变成高级流</td></tr></tbody></table><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public object readobject()</td><td>把序列化到本地文件中的对象，读取到程序中来</td></tr><tr><td>读出的类型还需要强转后才能还原真实的数据</td><td></td></tr></tbody></table><p>如果在序列化一个类后再对这个类进行更改,那么反序列化取出这个类时就会报错,这是因为在序列化时会自动记录一个版本号用以标识,更改了类中的成员它的版本号也会改变,而序列化取出的类版本号还是原来的就会不匹配</p><p>可以手动指出版本号,这样更改类中成员后版本号依旧没变</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Student implements Serializable{</span></span>
<span class="line"><span>	private static final long serialversionuID = 1L;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>需要在类中手动声明<code>private static final long serialversionuID</code>成员变量,修饰符等都不能更改</p><p>如果修改的类增加了新的成员变量,那么旧版本中的该成员变量默认值就为null 如果修改的类删除了成员变量,那么旧版本中的类就忽略该变量</p><p><strong>如果有的成员需要不序列化到本地文件中可以给这个成员添加<code>transient</code>关键字</strong> transient : 瞬态关键字 作用：该关键字标记的成员变量不参与序列化过程</p><h3 id="打印流" tabindex="-1"><a class="header-anchor" href="#打印流"><span>打印流</span></a></h3><p>PrintStream字节打印流 PrintWriter字符打印流</p><p>打印流只操作文件目的地，不操作数据源(只能写不能读) 特有的写出方法可以实现，数据原样写出</p><p>特有的写出方法，可以实现自动刷新，自动换行</p><h4 id="字节打印流" tabindex="-1"><a class="header-anchor" href="#字节打印流"><span>字节打印流</span></a></h4><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public PrintStream(OutputStream/File/String)</td><td>关联字节输出流/文件/文件路径</td></tr><tr><td>public PrintStream(String fileName, Charset charset)</td><td>指定字符编码</td></tr><tr><td>public PrintStream(OutputStream out, boolean autoFush)</td><td>自动刷新</td></tr><tr><td>public PrintStream(OutputStream out, boolean autoFlush, String encoding)</td><td>指定字符编码且自动刷新</td></tr><tr><td>字节流底层没有缓冲区,因此指定不指定自动刷新都是一样的</td><td></td></tr></tbody></table><p>打印都是原样打印,不会进行转换</p><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public voidwrite(int b)</td><td>常规方法：规则跟之前一样，将指定的字节写出</td></tr><tr><td>public void println(Xxx xx)</td><td>特有方法：打印任意数据，自动刷新，自动换行</td></tr><tr><td>public void print(Xxx xx)</td><td>特有方法：打印任意数据，不换行</td></tr><tr><td>public void printf(String format, Object... args)</td><td>特有方法：带有占位符的打印语句，不换行(格式化输出)</td></tr></tbody></table><h4 id="字符打印流" tabindex="-1"><a class="header-anchor" href="#字符打印流"><span>字符打印流</span></a></h4><p>方法和字节打印流一样</p><table><thead><tr><th>构造方法</th><th>说明</th></tr></thead><tbody><tr><td>public PrintWriter(Write/File/String)</td><td>关联字节输出流/文件/文件路径</td></tr><tr><td>public PrintWriter(String fileName, Charset charset)</td><td>指定字符编码</td></tr><tr><td>public PrintWriter(Write w, boolean autoFlush)</td><td>自动刷新</td></tr><tr><td>public PrintWriter(OutputStream out, boolean autoFlush, Charset charset)</td><td>指定字符编码且自动刷新<br></td></tr></tbody></table><table><thead><tr><th>成员方法</th><th>说明</th></tr></thead><tbody><tr><td>public void write(...)</td><td>常规方法：规则跟之前一样，写出字节或者字符串</td></tr><tr><td>public void println(Xxx xx)</td><td>特有方法：打印任意类型的数据并且换行</td></tr><tr><td>public void print(Xxx xx)</td><td>特有方法：打印任意类型的数据，不换行</td></tr><tr><td>public void printf(String format, Object... args)</td><td>特有方法：带有占位符的打印语句</td></tr></tbody></table><h3 id="压缩流与解压缩流" tabindex="-1"><a class="header-anchor" href="#压缩流与解压缩流"><span>压缩流与解压缩流</span></a></h3><p>解压的本质：把压缩包里面的每一个文件或者文件夹读取出来，按照层级拷贝到目的地当中</p><p>解压</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//1.创建一个File表示要解压的压缩包</span></span>
<span class="line"><span>File src = new File（pathname:：&quot;D:\\\\aaa.zip&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//2.创建一个File表示解压的目的地</span></span>
<span class="line"><span>File dest = new File( pathname:&quot;D:\\\\&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//创建一个解压缩流用来读取压缩包中的数据</span></span>
<span class="line"><span>ZipInputStream zip = new ZipInputStream(new FileInputStream(src));</span></span>
<span class="line"><span>//要先获取到压缩包里面的每一个zipentry对象</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//表示当前在压缩包中获取到的文件或者文件夹</span></span>
<span class="line"><span>ZipEntry entry;</span></span>
<span class="line"><span>while((entry = zip.getNextEntry()) != null){</span></span>
<span class="line"><span>	System.out.println(entry);</span></span>
<span class="line"><span>	if(entry.isDirectory()){</span></span>
<span class="line"><span>		//文件夹：需要在目的地dest处创建一个同样的文件夹</span></span>
<span class="line"><span>		File file = new File(dest,entry.toString());</span></span>
<span class="line"><span>		file.mkdirs();</span></span>
<span class="line"><span>	else{</span></span>
<span class="line"><span>		//文件：需要读取到压缩包中的文件，并把他存放到目的地dest文件夹中（按照层级目录进行存放）</span></span>
<span class="line"><span>		FileOutputStream fos = new FileOutputStream(new File(dest,entry.toString()));</span></span>
<span class="line"><span>		int b;</span></span>
<span class="line"><span>		while((b = zip.read()) != -1){</span></span>
<span class="line"><span>		//写到目的地</span></span>
<span class="line"><span>		fos.write(b);</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	fos.close();</span></span>
<span class="line"><span>	//表示在压缩包中的一个文件处理完毕了。</span></span>
<span class="line"><span>	zip.closeEntry();</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>zip.close();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>isDirectory()判断entry对象是否是一个文件夹 getNextEntry()获取下一个压缩包内的对象,以深搜的方式</p><p>压缩</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//1.创建File对象表示要压缩的文件</span></span>
<span class="line"><span>File src =new File（pathname:&quot;D:\\\\a.txt&quot;);</span></span>
<span class="line"><span>//2.创建File对象表示压缩包的位置</span></span>
<span class="line"><span>File dest = new File（pathname:：&quot;D:\\\\&quot;）;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7/1.创建压缩流关联压缩包</span></span>
<span class="line"><span>ZipOutputStream zos = new ZipoutputStream(new FileoutputStream(new File(dest, child: &quot;a.zip&quot;)));</span></span>
<span class="line"><span>//2.创建zipEntry对象，表示压缩包里面的每一个文件和文件夹</span></span>
<span class="line"><span>ZipEntry entry = new ZipEntry( name: &quot;a.txt&quot;);|</span></span>
<span class="line"><span>//3.把zipEntry对象放到压缩包当中</span></span>
<span class="line"><span>zos.putNextEntry(entry);</span></span>
<span class="line"><span>//4.把src文件中的数据写到压缩包当中</span></span>
<span class="line"><span>FileInputStream fis = new FileInputStream(src);</span></span>
<span class="line"><span>int b;</span></span>
<span class="line"><span>while((b = fis.read()) != -1){</span></span>
<span class="line"><span>	zos.write(b);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>zos.closeEntry();</span></span>
<span class="line"><span>zos.close();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="commons-io" tabindex="-1"><a class="header-anchor" href="#commons-io"><span>Commons-io</span></a></h1><p>Commons-io是apache开源基金组织提供的一组有关lO操作的开源工具包。 作用：提高IO流的开发效率。</p><table><thead><tr><th>FileUtils类（文件/文件夹相关）</th><th>说明</th></tr></thead><tbody><tr><td>static void copyFile(File srcFile, File destFile)</td><td>复制文件</td></tr><tr><td>static void copyDirectory(File srcDir, File destDir)</td><td>复制文件夹</td></tr><tr><td>static void copyDirectoryToDirectory(File srcDir, File destDir)</td><td>复制文件夹</td></tr><tr><td>static void deleteDirectory(File directory)</td><td>删除文件夹</td></tr><tr><td>static void cleanDirectory(File directory)</td><td>清空文件夹</td></tr><tr><td>static String readFileToString(File file, Charset encoding)</td><td>读取文件中的数据变成成字符串</td></tr><tr><td>static void write(File file, CharSequence data, String encoding)</td><td>写出数据</td></tr></tbody></table><table><thead><tr><th>IOUtils类（流相关相关）</th><th>说明</th></tr></thead><tbody><tr><td>public static int copy(InputStream input, OutputStream output)</td><td>复制文件</td></tr><tr><td>public static int copyLarge(Reader input, Writer output)</td><td>复制大文件</td></tr><tr><td>public static String readLines(Reader input)</td><td>读取数据</td></tr><tr><td>public static void write(String data, OutputStream output)</td><td>写出数据</td></tr></tbody></table><h1 id="hutool" tabindex="-1"><a class="header-anchor" href="#hutool"><span>Hutool</span></a></h1><table><thead><tr><th>相关类</th><th>说明</th></tr></thead><tbody><tr><td>IoUtil</td><td>流操作工具类</td></tr><tr><td>FileUtil</td><td>文件读写和操作的工具类</td></tr><tr><td>FileTypeUtil</td><td>文件类型判断工具类</td></tr><tr><td>WatchMonitor</td><td>目录、文件监听</td></tr><tr><td>ClassPathResource</td><td>针对ClassPath中资源的访问封装</td></tr><tr><td>FileReader</td><td>封装文件读取</td></tr><tr><td>FileWriter</td><td>封装文件写入</td></tr><tr><td>FileReader和FileWriter与官方的类名重了所以在导包时要注意</td><td></td></tr></tbody></table>`,165)]))}const p=e(n,[["render",d]]),c=JSON.parse('{"path":"/back/java/5/","title":"5 进阶","lang":"zh-CN","frontmatter":{"title":"5 进阶","createTime":"2025/04/05 12:12:26","permalink":"/back/java/5/"},"readingTime":{"minutes":18.45,"words":5535},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/5 进阶.md","headers":[]}');export{p as comp,c as data};
